#!/usr/bin/env python3
"""Overwrites template starter tones in SeedCatalog.json with hand-researched
per-song rigs ("gold tones"). Keyed by "Title|Artist"; matching is
normalization-tolerant. Usage: apply_gold_tones.py SeedCatalog.json
Entry: (tone_name, character, amp, (gain,bass,mid,treble,presence,reverb),
        guitar, pickup, [(pedal, type, [(knob, val)...], note)...], notes)
"""
import json
import re
import sys

TRANSLIT = str.maketrans("çğıöşüÇĞİÖŞÜâîûÂÎÛ", "cgiosuCGIOSUaiuAIU")


def norm(s):
    return re.sub(r"[^a-z0-9]+", " ", s.translate(TRANSLIT).lower()).strip()


