def to_tone(sid, idx, t):
    name, character, amp, s, guitar, pickup, pedals, notes = t
    g, b, m, tr, p, r = [float(x) for x in s]
    return {
        "id": f"{sid}-g{idx}", "name": name, "amp": amp.strip(), "character": character,
        "settings": {"gain": g, "bass": b, "mid": m, "treble": tr, "presence": p, "reverb": r},
        "guitar": guitar.strip(), "pickup": pickup.strip(),
        "pedals": [{
            "name": pn, "type": pt,
            "controls": [{"name": cn, "value": float(cv)} for cn, cv in pc],
            "note": pnote,
        } for (pn, pt, pc, pnote) in pedals],
        "notes": notes,
    }


def main():
    path = sys.argv[1]
    with open(path, encoding="utf-8") as f:
        songs = json.load(f)

    index = {}
    for song in songs:
        index[norm(song["title"]) + "|" + norm(song["artist"])] = song

    applied, missing = 0, []
    for key, tones in G.items():
        if tones is None:
            continue
        title, artist = key.split("|")
        k = norm(title) + "|" + norm(artist)
        song = index.get(k)
        if song is None:
            missing.append(key)
            continue
        song["tones"] = [to_tone(song["id"], i, t) for i, t in enumerate(tones)]
        applied += 1

    with open(path, "w", encoding="utf-8") as f:
        json.dump(songs, f, ensure_ascii=False)
    print(f"gold tones applied to {applied} songs")
    if missing:
        print(f"NOT FOUND ({len(missing)}): {missing}")


if __name__ == "__main__":
    main()
